        agent_identity: impl Into<String>,
        inner: Arc<dyn AuditSink>,
    ) -> Self {
        Self {
            run_id: run_id.into(),
            agent_identity: agent_identity.into(),
            workspace_path: None,
            inner,
            envelope_sink: None,
            events: Mutex::new(Vec::new()),
