    pub fn push_parent(&self, event_id: String) -> Result<(), WriteError> {
        let thread_id = std::thread::current().id();
        self.parent_stacks
            .lock()
            .map_err(|_| WriteError::Poisoned)?
            .entry(thread_id)
            .or_default()
            .push(event_id);
