fn invoke_transport(
    transport: &dyn LoopTransport,
    sink: &dyn AuditSink,
    cfg: &AgentLoopConfig,
    session_id: &str,
    iteration: u32,
    req: &TurnRequest<'_>,
) -> Result<TurnResponse, AgentLoopError> {
    let request_preview = preview_request(req, transport);
    let request_body_sha256 = sink.write_blob(&request_preview);
    sink.emit(&LoopAuditEvent::HttpRequest {
        ts: Utc::now(),
        run_id: cfg.run_id.clone(),
        session_id: session_id.to_string(),
        iteration,
        provider: transport.provider().to_string(),
        model: transport.model().to_string(),
        endpoint: String::new(),
        body_sha256: request_body_sha256,
    });

    let resp = transport.send_turn(req)?;

    let response_body_sha256 = sink.write_blob(&resp.raw_response_body);
    sink.emit(&LoopAuditEvent::HttpResponse {
        ts: Utc::now(),
        run_id: cfg.run_id.clone(),
        session_id: session_id.to_string(),
        iteration,
        http_status: resp.http_status,
        stop_reason: resp.stop_reason.as_str().to_string(),
        usage: UsageSnapshot {
            input_tokens: resp.usage.input_tokens,
            output_tokens: resp.usage.output_tokens,
            cache_read_input_tokens: resp.usage.cache_read_input_tokens,
            cache_creation_input_tokens: resp.usage.cache_creation_input_tokens,
        },
        body_sha256: response_body_sha256,
    });

    let _ = sink.write_blob(&resp.raw_request_body);

    Ok(resp)
}

pub trait AuditSink: Send + Sync {
    fn emit(&self, event: &LoopAuditEvent);
    fn write_blob(&self, content: &[u8]) -> String;
}

impl AuditSink for NullSink {
    fn emit(&self, _event: &LoopAuditEvent) {}
    fn write_blob(&self, _content: &[u8]) -> String {
        String::new()
    }
}

pub struct InMemorySink {
    events: Mutex<Vec<LoopAuditEvent>>,
    blobs: Mutex<Vec<(String, Vec<u8>)>>,
    blob_store: BlobStore,
}

pub fn events(&self) -> Vec<LoopAuditEvent> {
        self.events.lock().expect("audit mutex").clone()
    }

impl AuditSink for InMemorySink {
    fn emit(&self, event: &LoopAuditEvent) {
        self.events.lock().expect("audit mutex").push(event.clone());
    }
    fn write_blob(&self, content: &[u8]) -> String {
        let hash = self
            .blob_store
            .write(content)
            .unwrap_or_else(|err| format!("error:{err}"));
        self.blobs
            .lock()
            .expect("blob mutex")
            .push((hash.clone(), content.to_vec()));
        hash
    }
}

fn emit(&self, event: &LoopAuditEvent) {
        self.events.lock().expect("audit mutex").push(event.clone());
    }

impl AuditSink for JsonlFileSink {
    fn emit(&self, event: &LoopAuditEvent) {
        let line = match serde_json::to_string(event) {
            Ok(l) => l,
            Err(err) => {
                tracing::warn!("failed to serialize loop audit event: {err}");
                return;
            }
        };
        let mut w = self.writer.lock().expect("audit writer");
        if let Err(err) = writeln!(w, "{line}") {
            tracing::warn!("failed to write loop audit event: {err}");
            return;
        }
        let _ = w.flush();
    }

    fn write_blob(&self, content: &[u8]) -> String {
        self.blob_store
            .write(content)
            .unwrap_or_else(|err| format!("error:{err}"))
    }
}

fn emit(&self, event: &LoopAuditEvent) {
        let line = match serde_json::to_string(event) {
            Ok(l) => l,
            Err(err) => {
                tracing::warn!("failed to serialize loop audit event: {err}");
                return;
            }
        };
        let mut w = self.writer.lock().expect("audit writer");
        if let Err(err) = writeln!(w, "{line}") {
            tracing::warn!("failed to write loop audit event: {err}");
            return;
        }
        let _ = w.flush();
    }

pub fn ensure_spawn_emitted(
        &mut self,
        run_id: &str,
        task_id: Option<&str>,
        sink: &dyn AuditSink,
    ) {
        if self.spawn_emitted {
            return;
        }
        sink.emit(&LoopAuditEvent::SessionSpawn {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            provider: self.provider.clone(),
            model: self.model.clone(),
            task_id: task_id.map(|s| s.to_string()),
            audit_tag: self.audit_tag.clone(),
        });
        self.spawn_emitted = true;
    }

pub fn close(self, run_id: &str, sink: &dyn AuditSink) {
        sink.emit(&LoopAuditEvent::SessionClose {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            reason: "caller_closed".to_string(),
        });
    }

impl Session {
    pub fn new(
        provider: impl Into<String>,
        model: impl Into<String>,
        system_prompt: impl Into<String>,
        audit_tag: Option<String>,
    ) -> Self {
        let counter = SESSION_COUNTER.fetch_add(1, Ordering::Relaxed);
        let ts_us = Utc::now().timestamp_micros();
        let id = format!("S{ts_us:x}-{counter:x}");
        Self {
            id,
            provider: provider.into(),
            model: model.into(),
            system_prompt: system_prompt.into(),
            history: Vec::new(),
            audit_tag,
            spawn_emitted: false,
        }
    }

    pub fn id(&self) -> &str {
        &self.id
    }

    pub fn provider(&self) -> &str {
        &self.provider
    }

    pub fn model(&self) -> &str {
        &self.model
    }

    pub fn system_prompt(&self) -> &str {
        &self.system_prompt
    }

    pub fn audit_tag(&self) -> Option<&str> {
        self.audit_tag.as_deref()
    }

    pub fn history(&self) -> &[Message] {
        &self.history
    }

    pub fn history_mut(&mut self) -> &mut Vec<Message> {
        &mut self.history
    }

    pub fn append_message(&mut self, msg: Message) {
        self.history.push(msg);
    }

    pub fn ensure_spawn_emitted(
        &mut self,
        run_id: &str,
        task_id: Option<&str>,
        sink: &dyn AuditSink,
    ) {
        if self.spawn_emitted {
            return;
        }
        sink.emit(&LoopAuditEvent::SessionSpawn {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            provider: self.provider.clone(),
            model: self.model.clone(),
            task_id: task_id.map(|s| s.to_string()),
            audit_tag: self.audit_tag.clone(),
        });
        self.spawn_emitted = true;
    }

    /// Run one `AgentLoop` turn against this session. Thin wrapper that
    /// threads the runtime dependencies through to [`AgentLoop::run`].
    /// Appends the user prompt, runs the loop, appends the assistant reply;
    /// mutating, per AC contract.
    #[allow(clippy::too_many_arguments)]
    pub fn send(
        &mut self,
        cfg: &AgentLoopConfig,
        transport: &dyn LoopTransport,
        registry: &ToolRegistry,
        tool_ctx: &ToolContext,
        sink: &dyn AuditSink,
        user_prompt: &str,
    ) -> Result<LoopOutcome, AgentLoopError> {
        AgentLoop::run(self, cfg, transport, registry, tool_ctx, sink, user_prompt)
    }

    pub fn close(self, run_id: &str, sink: &dyn AuditSink) {
        sink.emit(&LoopAuditEvent::SessionClose {
            ts: Utc::now(),
            run_id: run_id.to_string(),
            session_id: self.id.clone(),
            reason: "caller_closed".to_string(),
        });
    }

    /// Close the session without emitting a SessionClose event. Use when the
    /// loop itself has already recorded the termination condition (e.g. a
    /// guardrail error was the "close" reason).
    pub fn drop_quiet(self) {}
}

fn smoke_loop_converge(samples: &Path, fixtures: &Path, audit_root: &Path) -> Result<(), String> {
    let fixture_path = fixtures.join("loop_review_fix.json");
    reset_replay_transport();
    unsafe {
        env::set_var(
            "ORBIT_V2_REPLAY_FIXTURE",
            fixture_path.display().to_string(),
        );
    }

    let events_res = run_sample(
        samples.join("loop_review_fix.yaml"),
        audit_root,
        "loop-converge",
        Value::Null,
        true,
        &[],
    );

    let (events, loop_events) = match events_res {
        Ok(events) => {
            let loop_events = take_last_loop_events();
            (events, loop_events)
        }
        Err(err) => {
            unsafe {
                env::remove_var("ORBIT_V2_REPLAY_FIXTURE");
            }
            return Err(err);
        }
    };
    unsafe {
        env::remove_var("ORBIT_V2_REPLAY_FIXTURE");
    }

    let iter_starts: Vec<_> = events
        .iter()
        .filter(|e| e.envelope.event_type == "loop.iteration.start")
        .collect();
    if iter_starts.len() < 2 {
        return Err(format!(
            "expected >=2 loop.iteration.start events, got {}",
            iter_starts.len()
        ));
    }
    let iter_ends: Vec<_> = events
        .iter()
        .filter(|e| e.envelope.event_type == "loop.iteration.end")
        .collect();
    let broke = iter_ends.iter().any(|e| {
        matches!(
            &e.kind,
            V2AuditEventKind::LoopIterationEnd { broke, .. } if *broke
        )
    });
    if !broke {
        return Err("no loop.iteration.end reported broke=true".into());
    }

    // Session persistence: every tool.call.* from loop_events should share
    // the same session_id across iterations.
    let session_ids: Vec<String> = loop_events
        .iter()
        .filter_map(|e| match e {
            LoopAuditEvent::ToolCallRequested { session_id, .. } => Some(session_id.clone()),
            LoopAuditEvent::ToolCallResult { session_id, .. } => Some(session_id.clone()),
            _ => None,
        })
        .collect();
    if session_ids.len() < 2 {
        return Err(format!(
            "expected >=2 tool.call.* events (one per iteration), got {}",
            session_ids.len()
        ));
    }
    let first = &session_ids[0];
    if !session_ids.iter().all(|s| s == first) {
        return Err(format!(
            "session_id varies across iterations: {session_ids:?}"
        ));
    }
    Ok(())
}

fn take_last_loop_events() -> Vec<LoopAuditEvent> {
    LAST_LOOP.lock().unwrap().clone()
}

fn smoke_dispatch_agent_loop(
    path: &std::path::Path,
    audit_root: &std::path::Path,
) -> Result<(), String> {
    let yaml = std::fs::read_to_string(path).map_err(|e| format!("read: {e}"))?;
    let asset = load_v2(&yaml)?;

    let run_id = "smoke-agent-001";
    let (writer, envelope, inner) = build_writer_and_sinks(audit_root, run_id);

    let ActivityV2Spec::AgentLoop(agent_spec) = &asset.spec.spec else {
        return Err("not an agent_loop spec".into());
    };
    let host = EchoHost;

    // Phase 3: ToolDenied is structural — setting the env triggers the replay
    // path, which scripts fs.write → loop denies → driver returns Err(ToolDenied).
    unsafe {
        env::set_var("ORBIT_V2_REPLAY", "tool_denial");
    }
    let result = drive_agent_loop(
        agent_spec,
        None,
        run_id,
        writer.clone(),
        &Value::Null,
        &host,
        asset.spec.fs_profile.as_deref(),
    );
    unsafe {
        env::remove_var("ORBIT_V2_REPLAY");
    }

    match result {
        Err(DispatchError::ToolDenied {
            tool_name,
            iteration,
        }) => {
            println!("  structural denial: tool={tool_name} iter={iteration}");
        }
        Ok(outcome) => {
            return Err(format!("expected Err(ToolDenied), got Ok: {outcome:?}"));
        }
        Err(other) => {
